async fn handle_addstyle(cmd: &Value, state: &DaemonState) -> Result<Value, String> {
    let mgr = state.browser.as_ref().ok_or("Browser not launched")?;
    let content = cmd
        .get("content")
        .or_else(|| cmd.get("css"))
        .and_then(|v| v.as_str());
    let url = cmd.get("url").and_then(|v| v.as_str());

    if content.is_none() && url.is_none() {
        return Err("At least one of 'content' or 'url' is required".to_string());
    }

    if let Some(href) = url {
        let js = format!(
            r#"new Promise((resolve, reject) => {{
                const link = document.createElement('link');
                link.rel = 'stylesheet';
                link.href = {};
                link.onload = () => resolve(true);
                link.onerror = () => reject(new Error('Failed to load stylesheet'));
                document.head.appendChild(link);
            }})"#,
            serde_json::to_string(href).unwrap_or_default()
        );
        mgr.evaluate(&js, None).await?;
    } else if let Some(css) = content {
        let js = format!(
            r#"(() => {{
                const style = document.createElement('style');
                style.textContent = {};
                document.head.appendChild(style);
            }})()"#,
            serde_json::to_string(css).unwrap_or_default()
        );
        mgr.evaluate(&js, None).await?;
    }

    Ok(json!({ "added": true }))
}

async fn handle_clipboard(cmd: &Value, state: &DaemonState) -> Result<Value, String> {
    let mgr = state.browser.as_ref().ok_or("Browser not launched")?;
    let action = cmd
        .get("subAction")
        .or_else(|| cmd.get("operation"))
        .and_then(|v| v.as_str())
        .unwrap_or("read");

    let session_id = mgr.active_session_id()?.to_string();

    // cfg! is compile-time; assumes the browser runs on the same OS as the CLI binary.
    let modifier: i32 = if cfg!(target_os = "macos") { 4 } else { 2 };

    match action {
        "write" => {
            let text = cmd
                .get("text")
                .or_else(|| cmd.get("value"))
                .and_then(|v| v.as_str())
                .ok_or("Missing 'text' parameter")?;
            let js = format!(
                "navigator.clipboard.writeText({})",
                serde_json::to_string(text).unwrap_or_default()
            );
            mgr.evaluate(&js, None).await?;
            Ok(json!({ "written": text }))
        }
        "copy" => {
            interaction::press_key_with_modifiers(&mgr.client, &session_id, "c", Some(modifier))
                .await?;
            Ok(json!({ "copied": true }))
        }
        "paste" => {
            interaction::press_key_with_modifiers(&mgr.client, &session_id, "v", Some(modifier))
                .await?;
            Ok(json!({ "pasted": true }))
        }
        _ => {
            let result = mgr.evaluate("navigator.clipboard.readText()", None).await?;
            Ok(json!({ "text": result }))
        }
    }
}

async fn handle_wheel(cmd: &Value, state: &DaemonState) -> Result<Value, String> {
    let mgr = state.browser.as_ref().ok_or("Browser not launched")?;
    let session_id = mgr.active_session_id()?.to_string();
    let x = cmd.get("x").and_then(|v| v.as_f64()).unwrap_or(0.0);
    let y = cmd.get("y").and_then(|v| v.as_f64()).unwrap_or(0.0);
    let delta_x = cmd.get("deltaX").and_then(|v| v.as_f64()).unwrap_or(0.0);
    let delta_y = cmd.get("deltaY").and_then(|v| v.as_f64()).unwrap_or(0.0);

    mgr.client
        .send_command(
            "Input.dispatchMouseEvent",
            Some(json!({
                "type": "mouseWheel",
                "x": x,
                "y": y,
                "deltaX": delta_x,
                "deltaY": delta_y,
            })),
            Some(&session_id),
        )
        .await?;

    Ok(json!({ "scrolled": true, "deltaX": delta_x, "deltaY": delta_y }))
}

async fn handle_device(cmd: &Value, state: &DaemonState) -> Result<Value, String> {
    let mgr = state.browser.as_ref().ok_or("Browser not launched")?;
    let name = cmd
        .get("name")
        .or_else(|| cmd.get("device"))
        .and_then(|v| v.as_str())
        .ok_or("Missing 'name' parameter")?;

    let (width, height, scale, mobile, ua) = match name.to_lowercase().as_str() {
        "iphone 15" | "iphone15" => (393, 852, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 Mobile/15E148 Safari/604.1"),
        "iphone 16" | "iphone16" => (393, 852, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 18_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.0 Mobile/15E148 Safari/604.1"),
        "iphone 16 pro" | "iphone16pro" => (402, 874, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 18_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.0 Mobile/15E148 Safari/604.1"),
        "iphone 17" | "iphone17" => (402, 874, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 19_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/19.0 Mobile/15E148 Safari/604.1"),
        "ipad" | "ipad air" => (820, 1180, 2.0, true, "Mozilla/5.0 (iPad; CPU OS 18_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.0 Safari/604.1"),
        "ipad pro" => (1024, 1366, 2.0, true, "Mozilla/5.0 (iPad; CPU OS 18_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.0 Safari/604.1"),
        "pixel 9" | "pixel9" => (412, 923, 2.625, true, "Mozilla/5.0 (Linux; Android 15; Pixel 9) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/130.0.0.0 Mobile Safari/537.36"),
        "galaxy s25" | "galaxys25" => (360, 800, 3.0, true, "Mozilla/5.0 (Linux; Android 15; SM-S931B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/130.0.0.0 Mobile Safari/537.36"),
        // Legacy aliases
        "iphone 12" | "iphone12" => (390, 844, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 14_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/14.0 Mobile/15E148 Safari/604.1"),
        "iphone 14" | "iphone14" => (390, 844, 3.0, true, "Mozilla/5.0 (iPhone; CPU iPhone OS 16_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/16.0 Mobile/15E148 Safari/604.1"),
        "pixel 5" | "pixel5" => (393, 851, 2.75, true, "Mozilla/5.0 (Linux; Android 11; Pixel 5) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/90.0.4430.91 Mobile Safari/537.36"),
        "pixel 7" | "pixel7" => (412, 915, 2.625, true, "Mozilla/5.0 (Linux; Android 13; Pixel 7) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/116.0.0.0 Mobile Safari/537.36"),
        "galaxy s21" | "galaxys21" => (360, 800, 3.0, true, "Mozilla/5.0 (Linux; Android 11; SM-G991B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/90.0.4430.91 Mobile Safari/537.36"),
        _ => return Err(format!("Unknown device: {}. Supported: iPhone 15, iPhone 16, iPhone 16 Pro, iPhone 17, iPad, iPad Pro, Pixel 9, Galaxy S25", name)),
    };

    mgr.set_viewport(width, height, scale, mobile).await?;
    mgr.set_user_agent(ua).await?;

    // Update stream server viewport so status messages and screencast use the new dimensions
    if let Some(ref server) = state.stream_server {
        server.set_viewport(width as u32, height as u32).await;
    }

    Ok(json!({
        "device": name,
        "width": width,
        "height": height,
        "deviceScaleFactor": scale,
        "mobile": mobile,
    }))
}

// ---------------------------------------------------------------------------
// Stream handlers
// ---------------------------------------------------------------------------

fn stream_file_path(session_id: &str) -> PathBuf {
    get_socket_dir().join(format!("{}.stream", session_id))
}

fn write_stream_file(session_id: &str, port: u16) -> Result<(), String> {
    let path = stream_file_path(session_id);
    fs::write(&path, port.to_string()).map_err(|e| {
        format!(
            "Failed to write stream metadata '{}': {}",
            path.display(),
            e
        )
    })
}

fn remove_stream_file(session_id: &str) -> Result<(), String> {
    let path = stream_file_path(session_id);
    match fs::remove_file(&path) {
        Ok(()) => Ok(()),
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => Ok(()),
        Err(err) => Err(format!(
            "Failed to remove stream metadata '{}': {}",
            path.display(),
            err
        )),
    }
}

fn engine_file_path(session_id: &str) -> PathBuf {
    get_socket_dir().join(format!("{}.engine", session_id))
}

fn write_engine_file(session_id: &str, engine: &str) {
    let _ = fs::write(engine_file_path(session_id), engine);
}

fn remove_engine_file(session_id: &str) {
    let _ = fs::remove_file(engine_file_path(session_id));
}

fn provider_file_path(session_id: &str) -> PathBuf {
    get_socket_dir().join(format!("{}.provider", session_id))
}

fn write_provider_file(session_id: &str, provider: &str) {
    let _ = fs::write(provider_file_path(session_id), provider);
}

fn remove_provider_file(session_id: &str) {
    let _ = fs::remove_file(provider_file_path(session_id));
}

fn extensions_file_path(session_id: &str) -> PathBuf {
    get_socket_dir().join(format!("{}.extensions", session_id))
}

fn write_extensions_file(session_id: &str) {
    if let Ok(val) = env::var("AGENT_BROWSER_EXTENSIONS") {
        let trimmed = val.trim();
        if !trimmed.is_empty() {
            let _ = fs::write(extensions_file_path(session_id), trimmed);
            return;
        }
    }
    let _ = fs::remove_file(extensions_file_path(session_id));
}

fn remove_extensions_file(session_id: &str) {
    let _ = fs::remove_file(extensions_file_path(session_id));
}

async fn current_stream_status(state: &DaemonState) -> Value {
    debug_assert_eq!(
        state.stream_server.is_some(),
        state.stream_client.is_some(),
        "stream server and stream client slot should be set together"
    );

    let connected = match state.browser.as_ref() {
        Some(mgr) => mgr.is_connection_alive().await,
        None => false,
    };
    let runtime_screencasting = match state.stream_server.as_ref() {
        Some(server) => server.is_screencasting().await,
        None => false,
    };

    json!({
        "enabled": state.stream_server.is_some(),
        "port": state
            .stream_server
            .as_ref()
            .map(|server| Value::from(server.port()))
            .unwrap_or(Value::Null),
        "connected": connected,
        "screencasting": connected && (state.screencasting || runtime_screencasting),
    })
}

async fn handle_stream_enable(cmd: &Value, state: &mut DaemonState) -> Result<Value, String> {
    if state.stream_server.is_some() {
        return Err("Streaming is already enabled for this session".to_string());
    }

    let requested_port = match cmd.get("port").and_then(|value| value.as_u64()) {
        Some(raw) => u16::try_from(raw)
            .map_err(|_| format!("Invalid stream port '{}': expected 0-65535", raw))?,
        None => 0,
    };

    let (server, client_slot) =
        StreamServer::start_without_client(requested_port, state.session_id.clone(), false).await?;
    let port = server.port();
    if let Err(err) = write_stream_file(&state.session_id, port) {
        server.shutdown().await;
        return Err(err);
    }

    state.stream_client = Some(client_slot);
    state.stream_server = Some(Arc::new(server));
    state.request_tracking = true;
    if state.screencasting {
        if let Some(ref server) = state.stream_server {
            server.set_screencasting(true).await;
        }
    }
    state.update_stream_client().await;

    Ok(current_stream_status(state).await)
}

async fn handle_stream_disable(state: &mut DaemonState) -> Result<Value, String> {
    let Some(server) = state.stream_server.clone() else {
        return Err("Streaming is not enabled for this session".to_string());
    };

    server.shutdown().await;
    state.stream_server = None;
    state.stream_client = None;
    remove_stream_file(&state.session_id)?;
    remove_engine_file(&state.session_id);
    remove_provider_file(&state.session_id);

    Ok(json!({ "disabled": true }))
}

async fn handle_stream_status(state: &DaemonState) -> Result<Value, String> {
    Ok(current_stream_status(state).await)
}

async fn handle_service_status(cmd: &Value) -> Result<Value, String> {
    let mut service_state = cmd
        .get("serviceState")
        .cloned()
        .map(serde_json::from_value::<ServiceState>)
        .transpose()
        .map_err(|err| format!("Invalid serviceState: {}", err))?
        .unwrap_or_default();
    let waiting_profile_lease_job_count = service_state
        .jobs
        .values()
        .filter(|job| job.state == ServiceJobState::WaitingProfileLease)
        .count();
    if let Some(control_plane) = service_state.control_plane.as_mut() {
        control_plane.waiting_profile_lease_job_count = waiting_profile_lease_job_count;
    } else {
        service_state.control_plane = Some(super::service_model::ControlPlaneSnapshot {
            waiting_profile_lease_job_count,
            ..super::service_model::ControlPlaneSnapshot::default()
        });
    }
    refresh_remote_view_stream_urls(&mut service_state);
    refresh_cdp_screencast_view_streams(&mut service_state);
    service_state.refresh_profile_readiness();

    let profile_allocations = service_profile_allocations(&service_state);
    let launch_config = cmd
        .get("launchConfig")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let mut service_state_json =
        serde_json::to_value(&service_state).map_err(|err| err.to_string())?;
    inject_browser_process_stats(&mut service_state_json);

    Ok(json!({
        "service_state": service_state_json,
        "profileAllocations": profile_allocations,
        "launchConfig": launch_config,
    }))
}

async fn handle_service_resources(cmd: &Value) -> Result<Value, String> {
    let service_state = load_service_state_for_maintenance(cmd)?;
    Ok(service_resources_response(&service_state))
}

async fn handle_service_resources_monitor_summary() -> Result<Value, String> {
    service_resources_monitor_summary_response()
}

async fn handle_service_resources_write_monitor_summary(cmd: &Value) -> Result<Value, String> {
    let service_state = load_service_state_for_maintenance(cmd)?;
    service_resources_write_monitor_summary_response(&service_state)
}

async fn handle_service_gc(cmd: &Value) -> Result<Value, String> {
    let apply = cmd.get("apply").and_then(Value::as_bool).unwrap_or(false);
    if apply {
        let review_token = cmd.get("reviewToken").and_then(Value::as_str);
        let force_without_review = cmd
            .get("forceWithoutReview")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let repository = LockedServiceStateRepository::default_json()?;
        repository.mutate(|state| {
            let response = service_gc_apply_response(state, review_token, force_without_review);
            if let Some(error) = response.get("error").and_then(Value::as_str) {
                Err(error.to_string())
            } else {
                Ok(response)
            }
        })
    } else {
        let service_state = load_service_state_for_maintenance(cmd)?;
        Ok(service_gc_dry_run_response(&service_state))
    }
}

fn load_service_state_for_maintenance(cmd: &Value) -> Result<ServiceState, String> {
    if let Some(service_state) = cmd.get("serviceState") {
        serde_json::from_value::<ServiceState>(service_state.clone())
            .map_err(|err| format!("Invalid serviceState: {}", err))
    } else {
        LockedServiceStateRepository::default_json()?.load_snapshot()
    }
}

fn inject_browser_process_stats(service_state: &mut Value) {
    let Some(browsers) = service_state
        .get_mut("browsers")
        .and_then(|value| value.as_object_mut())
    else {
        return;
    };
    for browser in browsers.values_mut() {
        let pid = browser
            .get("pid")
            .and_then(|value| value.as_u64())
            .and_then(|value| u32::try_from(value).ok());
        if let Some(pid) = pid.and_then(process_stats_for_pid) {
            browser["processStats"] = pid;
        }
    }
}

fn process_stats_for_pid(pid: u32) -> Option<Value> {
    #[cfg(target_os = "linux")]
    {
        linux_process_stats_for_pid(pid)
    }
    #[cfg(not(target_os = "linux"))]
    {
        let _ = pid;
        None
    }
}

#[cfg(target_os = "linux")]
fn linux_process_stats_for_pid(pid: u32) -> Option<Value> {
    let stat = fs::read_to_string(format!("/proc/{pid}/stat")).ok()?;
    let stat_tail = stat.rsplit_once(") ")?.1;
    let fields = stat_tail.split_whitespace().collect::<Vec<_>>();
    let clock_ticks = 100.0_f64;
    let utime = fields
        .get(11)
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(0);
    let stime = fields
        .get(12)
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(0);
    let rss_bytes = fs::read_to_string(format!("/proc/{pid}/status"))
        .ok()
        .and_then(|status| {
            status.lines().find_map(|line| {
                let value = line.strip_prefix("VmRSS:")?.split_whitespace().next()?;
                value.parse::<u64>().ok().map(|kib| kib * 1024)
            })
        });
    let mut stats = json!({
        "pid": pid,
        "running": pid_is_running(pid),
        "cpuSeconds": ((utime + stime) as f64 / clock_ticks),
    });
    if let Some(bytes) = rss_bytes {
        stats["rssBytes"] = json!(bytes);
    }
    Some(stats)
}

/// Return the no-launch service access plan from the current service state.
async fn handle_service_access_plan(cmd: &Value) -> Result<Value, String> {
    let mut service_state = cmd
        .get("serviceState")
        .cloned()
        .map(serde_json::from_value::<ServiceState>)
        .transpose()
        .map_err(|err| format!("Invalid serviceState: {}", err))?
        .unwrap_or_default();
    service_state.refresh_profile_readiness();

    let request = ServiceAccessPlanRequest {
        service_name: optional_command_string(cmd, "serviceName"),
        agent_name: optional_command_string(cmd, "agentName"),
        task_name: optional_command_string(cmd, "taskName"),
        target_service_ids: target_service_ids_from_command(cmd),
        account_ids: account_ids_from_command(cmd),
        target_url: target_url_from_command(cmd),
        site_policy_id: optional_command_string(cmd, "sitePolicyId"),
        challenge_id: optional_command_string(cmd, "challengeId"),
        readiness_profile_id: optional_command_string(cmd, "readinessProfileId"),
        browser_build: browser_build_from_command(cmd),
        browser_build_explicit: cmd.get("browserBuild").and_then(Value::as_str).is_some(),
        browser_host: browser_host_from_command(cmd),
        view_stream_provider: optional_command_string(cmd, "viewStreamProvider")
            .or_else(|| optional_command_string(cmd, "viewStream"))
            .or_else(|| {
                cmd.get("params").and_then(|params| {
                    optional_command_string(params, "viewStreamProvider")
                        .or_else(|| optional_command_string(params, "viewStream"))
                })
            })
            .and_then(|value| parse_view_stream_provider(&value)),
        control_input_provider: optional_command_string(cmd, "controlInputProvider")
            .or_else(|| optional_command_string(cmd, "controlInput"))
            .or_else(|| {
                cmd.get("params").and_then(|params| {
                    optional_command_string(params, "controlInputProvider")
                        .or_else(|| optional_command_string(params, "controlInput"))
                })
            })
            .and_then(|value| parse_control_input_provider(&value)),
        display_isolation: remote_headed_display_isolation_from_command(cmd),
    };

    let mut plan = service_access_plan_for_state(&service_state, request);
    let summary = access_plan_browser_build_selection_summary(&plan);
    if let Some(object) = plan.as_object_mut() {
        object.insert("browserBuildSelectionSummary".to_string(), summary);
    }
    Ok(plan)
}

fn access_plan_browser_build_selection_summary(plan: &Value) -> Value {
    let selection = plan
        .pointer("/decision/launchPosture/browserBuildSelection")
        .unwrap_or(&Value::Null);
    let profile_compatibility = selection
        .get("profileCompatibility")
        .unwrap_or(&Value::Null);
    let validation_evidence = selection.get("validationEvidence").unwrap_or(&Value::Null);
    let browser_build = optional_command_string(selection, "browserBuild");
    let source = optional_command_string(selection, "source");
    let evidence_source = optional_command_string(selection, "evidenceSource");
    let profile_compatibility_status = optional_command_string(profile_compatibility, "status");
    let validation_evidence_status = optional_command_string(validation_evidence, "status");
    let selected_preference_binding_id =
        optional_command_string(selection, "selectedPreferenceBindingId");
    let mut compact_parts = vec![
        format!("build={}", browser_build.as_deref().unwrap_or("unknown")),
        format!("source={}", source.as_deref().unwrap_or("unknown")),
        format!(
            "evidence={}",
            evidence_source.as_deref().unwrap_or("unknown")
        ),
        format!(
            "override={}",
            if selection
                .get("operatorOverride")
                .and_then(Value::as_bool)
                .unwrap_or(false)
            {
                "yes"
            } else {
                "no"
            }
        ),
        format!(
            "profileCompatibility={}",
            profile_compatibility_status.as_deref().unwrap_or("unknown")
        ),
        format!(
            "validation={}",
            validation_evidence_status.as_deref().unwrap_or("unknown")
        ),
    ];
    if let Some(binding_id) = selected_preference_binding_id.as_deref() {
        compact_parts.push(format!("preferenceBinding={binding_id}"));
    }
    let mut audit_flags = Vec::new();
    if source.as_deref() == Some("browser_preference_binding") {
        audit_flags.push("preference_binding_selected");
    }
    if selection
        .get("operatorOverride")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        audit_flags.push("operator_override");
    }
    if selection
        .get("requiresCdpFree")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        audit_flags.push("requires_cdp_free");
    }
    if profile_compatibility_status.as_deref() == Some("incompatible_or_mixed") {
        audit_flags.push("profile_compatibility_attention");
    }
    if matches!(
        validation_evidence_status.as_deref(),
        Some("failed_or_mixed" | "missing")
    ) {
        audit_flags.push("validation_evidence_attention");
    }
    let attention_required = audit_flags.iter().any(|flag| flag.ends_with("_attention"));
    json!({
        "browserBuild": browser_build,
        "source": source,
        "evidenceSource": evidence_source,
        "summary": optional_command_string(selection, "summary"),
        "operatorOverride": selection.get("operatorOverride").and_then(Value::as_bool).unwrap_or(false),
        "requiresCdpFree": selection.get("requiresCdpFree").and_then(Value::as_bool).unwrap_or(false),
        "selectedProfileId": optional_command_string(selection, "selectedProfileId"),
        "selectedProfileBrowserBuild": optional_command_string(selection, "selectedProfileBrowserBuild"),
        "selectedPreferenceBindingId": selected_preference_binding_id,
        "selectedPreferenceBindingReason": optional_command_string(selection, "selectedPreferenceBindingReason"),
        "profileCompatibilityStatus": profile_compatibility_status,
        "profileCompatibilityReason": optional_command_string(profile_compatibility, "reason"),
        "profileCompatibilityIds": string_array_field(profile_compatibility, "matchingIds"),
        "validationEvidenceStatus": validation_evidence_status,
        "validationEvidenceReason": optional_command_string(validation_evidence, "reason"),
        "validationEvidenceIds": string_array_field(validation_evidence, "matchingIds"),
        "auditFlags": audit_flags,
        "attentionRequired": attention_required,
        "compact": compact_parts.join(" "),
    })
}

fn string_array_field(value: &Value, key: &str) -> Vec<String> {
    value
        .get(key)
        .and_then(Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

/// Evaluate browser capability launch gates without starting Chrome.
async fn handle_service_browser_capability_preflight(cmd: &Value) -> Result<Value, String> {
    let requested_build = browser_build_from_command(cmd);
    let cdp_free = cmd
        .get("requiresCdpFree")
        .or_else(|| cmd.get("cdpFree"))
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || requested_build == Some(BrowserBuild::CdpFreeHeaded)
        || cmd
            .get("cdpAttachmentAllowed")
            .and_then(Value::as_bool)
            .is_some_and(|allowed| !allowed);
    let headless = if cdp_free {
        false
    } else {
        cmd.get("headless").and_then(Value::as_bool).unwrap_or(true)
    };
    let mut launch_options = LaunchOptions {
        headless,
        executable_path: cmd
            .get("executablePath")
            .and_then(|value| value.as_str())
            .map(str::to_string)
            .or_else(|| env::var("AGENT_BROWSER_EXECUTABLE_PATH").ok()),
        profile: launch_profile_from_sources(cmd, true),
        runtime_profile: cmd
            .get("runtimeProfile")
            .and_then(|value| value.as_str())
            .map(str::to_string)
            .or_else(runtime_profile_from_env),
        manual_login: cdp_free,
        attachable: !cdp_free,
        ..LaunchOptions::default()
    };
    let browser_capability_launch =
        apply_service_browser_capability_selection(&mut launch_options, cmd);
    Ok(json!({
        "preflight": true,
        "wouldLaunch": false,
        "wouldApplyExecutable": browser_capability_launch.applied,
        "browserCapabilityLaunch": browser_capability_launch.to_value(),
        "request": {
            "browserBuild": requested_build.map(browser_build_label),
            "profileId": service_profile_id(
                launch_options.profile.as_deref(),
                launch_options.runtime_profile.as_deref()
            ),
            "headless": launch_options.headless,
            "cdpFree": cdp_free,
            "serviceName": optional_command_string(cmd, "serviceName"),
            "agentName": optional_command_string(cmd, "agentName"),
            "taskName": optional_command_string(cmd, "taskName"),
            "targetServiceIds": target_service_ids_from_command(cmd),
            "accountIds": account_ids_from_command(cmd),
            "url": target_url_from_command(cmd),
        },
        "selectedExecutablePath": launch_options.executable_path,
    }))
}

/// Generate operator-facing commands for binding a site/account to a known browser executable.
async fn handle_service_browser_capability_preference_guide(cmd: &Value) -> Result<Value, String> {
    let service_state = cmd
        .get("serviceState")
        .cloned()
        .map(serde_json::from_value::<ServiceState>)
        .transpose()
        .map_err(|err| format!("Invalid serviceState: {}", err))?
        .unwrap_or_default();
    Ok(browser_capability_preference_guide(&service_state, cmd))
}

fn browser_capability_preference_guide(service_state: &ServiceState, cmd: &Value) -> Value {
    let registry = &service_state.browser_capability_registry;
    let requested_build = optional_command_string(cmd, "browserBuild");
    let target_service_ids = target_service_ids_from_command(cmd);
    let account_ids = account_ids_from_command(cmd);
    let service_name = optional_command_string(cmd, "serviceName");
    let task_name = optional_command_string(cmd, "taskName");
    let reason = optional_command_string(cmd, "reason")
        .unwrap_or_else(|| "operator_primary_browser_preference".to_string());
    let has_filter = !target_service_ids.is_empty()
        || !account_ids.is_empty()
        || service_name.is_some()
        || task_name.is_some();
    let mut suggestions = registry
        .browser_executables
        .iter()
        .filter(|executable| {
            requested_build.as_deref().is_none_or(|build| {
                registry_string_field(executable, "buildLabel").as_deref() == Some(build)
            })
        })
        .filter_map(|executable| {
            let executable_id = registry_string_field(executable, "id")?;
            let browser_build = registry_string_field(executable, "buildLabel")
                .or_else(|| requested_build.clone())
                .unwrap_or_else(|| "stock_chrome".to_string());
            let host_id = registry_string_field(executable, "hostId");
            let capability_id =
                matching_capability_id(registry, host_id.as_deref(), &executable_id);
            let command = browser_preference_command(BrowserPreferenceCommandInput {
                browser_build: &browser_build,
                executable_id: &executable_id,
                host_id: host_id.as_deref(),
                capability_id: capability_id.as_deref(),
                target_service_ids: &target_service_ids,
                account_ids: &account_ids,
                service_name: service_name.as_deref(),
                task_name: task_name.as_deref(),
                reason: &reason,
            });
            let existing_binding_ids = registry
                .browser_preference_bindings
                .iter()
                .filter(|binding| {
                    registry_string_field(binding, "preferredExecutableId").as_deref()
                        == Some(executable_id.as_str())
                })
                .filter_map(|binding| registry_string_field(binding, "id"))
                .collect::<Vec<_>>();
            Some(json!({
                "executableId": executable_id,
                "browserBuild": browser_build,
                "hostId": host_id,
                "capabilityId": capability_id,
                "source": registry_string_field(executable, "source"),
                "executablePath": registry_string_field(executable, "executablePath"),
                "fresh": executable.get("fresh").cloned().unwrap_or(Value::Null),
                "tags": executable.get("tags").cloned().unwrap_or_else(|| json!([])),
                "existingBindingIds": existing_binding_ids,
                "copyable": has_filter,
                "command": command,
            }))
        })
        .collect::<Vec<_>>();
    suggestions.sort_by(|left, right| {
        json_string_field(left, "browserBuild")
            .cmp(&json_string_field(right, "browserBuild"))
            .then_with(|| {
                json_string_field(left, "executableId")
                    .cmp(&json_string_field(right, "executableId"))
            })
    });

    json!({
        "guide": true,
        "advisory": true,
        "copyable": has_filter,
        "requested": {
            "browserBuild": requested_build,
            "targetServiceIds": target_service_ids,
            "accountIds": account_ids,
            "serviceName": service_name,
            "taskName": task_name,
            "reason": reason,
        },
        "counts": {
            "browserExecutables": registry.browser_executables.len(),
            "matchingExecutables": suggestions.len(),
            "browserPreferenceBindings": registry.browser_preference_bindings.len(),
        },
        "suggestions": suggestions,
        "recommendedNextStep": if has_filter {
            "Copy the preferred command, run it, then run service browser-capability preflight for the same site/account before requesting browser work."
        } else {
            "Rerun with --target-service-id and --account-id to produce exact copyable prefer commands."
        },
    })
}

fn json_string_field(value: &Value, field: &str) -> String {
    value
        .get(field)
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_string()
}

fn matching_capability_id(
    registry: &BrowserCapabilityRegistry,
    host_id: Option<&str>,
    executable_id: &str,
) -> Option<String> {
    registry.browser_capabilities.iter().find_map(|capability| {
        let executable_matches =
            registry_string_field(capability, "executableId").as_deref() == Some(executable_id);
        let host_matches = host_id.is_none_or(|host_id| {
            registry_string_field(capability, "hostId").as_deref() == Some(host_id)
        });
        (executable_matches && host_matches).then(|| registry_string_field(capability, "id"))?
    })
}

struct BrowserPreferenceCommandInput<'a> {
    browser_build: &'a str,
    executable_id: &'a str,
    host_id: Option<&'a str>,
    capability_id: Option<&'a str>,
    target_service_ids: &'a [String],
    account_ids: &'a [String],
    service_name: Option<&'a str>,
    task_name: Option<&'a str>,
    reason: &'a str,
}

fn browser_preference_command(input: BrowserPreferenceCommandInput<'_>) -> String {
    let mut args = vec![
        "agent-browser".to_string(),
        "service".to_string(),
        "browser-capability".to_string(),
        "prefer".to_string(),
        "--browser-build".to_string(),
        input.browser_build.to_string(),
        "--preferred-executable-id".to_string(),
        input.executable_id.to_string(),
    ];
    if let Some(host_id) = input.host_id {
        args.push("--preferred-host-id".to_string());
        args.push(host_id.to_string());
    }
    if let Some(capability_id) = input.capability_id {
        args.push("--preferred-capability-id".to_string());
        args.push(capability_id.to_string());
    }
    if input.target_service_ids.is_empty()
        && input.account_ids.is_empty()
        && input.service_name.is_none()
        && input.task_name.is_none()
    {
        args.push("--target-service-id".to_string());
        args.push("<site>".to_string());
        args.push("--account-id".to_string());
        args.push("<account>".to_string());
    } else {
        for target in input.target_service_ids {
            args.push("--target-service-id".to_string());
            args.push(target.clone());
        }
        for account in input.account_ids {
            args.push("--account-id".to_string());
            args.push(account.clone());
        }
        if let Some(service_name) = input.service_name {
            args.push("--service-name".to_string());
            args.push(service_name.to_string());
        }
        if let Some(task_name) = input.task_name {
            args.push("--task-name".to_string());
            args.push(task_name.to_string());
        }
    }
    args.push("--reason".to_string());
    args.push(input.reason.to_string());
    args.into_iter()
        .map(|arg| shell_quote_command_arg(&arg))
        .collect::<Vec<_>>()
        .join(" ")
}

fn shell_quote_command_arg(arg: &str) -> String {
    if arg.starts_with('<') && arg.ends_with('>') {
        return arg.to_string();
    }
    if arg
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.' | '/' | ':' | '='))
    {
        arg.to_string()
    } else {
        format!("'{}'", arg.replace('\'', "'\\''"))
    }
}

/// Return the service-owned profile collection without the full status payload.
async fn handle_service_profiles(cmd: &Value) -> Result<Value, String> {
    let mut service_state = cmd
        .get("serviceState")
        .cloned()
        .map(serde_json::from_value::<ServiceState>)
        .transpose()
        .map_err(|err| format!("Invalid serviceState: {}", err))?
        .unwrap_or_default();
    service_state.refresh_profile_readiness();
    let profile_allocations = service_profile_allocations(&service_state);
    let profile_sources = service_profile_sources(&service_state);
    let mut profiles = service_state.profiles.into_values().collect::<Vec<_>>();
    profiles.sort_by(|left, right| left.id.cmp(&right.id));
    let count = profiles.len();

    Ok(json!({
        "profiles": profiles,
        "profileSources": profile_sources,
        "profileAllocations": profile_allocations,
        "count": count,
    }))
}

async fn handle_service_profile_seeding_handoff(cmd: &Value) -> Result<Value, String> {
    let mut service_state = cmd
        .get("serviceState")
        .cloned()
        .map(serde_json::from_value::<ServiceState>)
        .transpose()
        .map_err(|err| format!("Invalid serviceState: {}", err))?
        .unwrap_or_default();
    service_state.refresh_profile_readiness();
    let profile_id = cmd
        .get("profileId")
        .and_then(|value| value.as_str())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "service_profile_seeding_handoff requires profileId".to_string())?;
    let target_service_id = cmd
        .get("targetServiceId")
        .and_then(|value| value.as_str())
        .filter(|value| !value.is_empty());
    service_profile_seeding_handoff(&service_state, profile_id, target_service_id)
}

